output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?opponent ?opponentLabel WHERE {
  ?opponent wdt:P4182 wd:Q3310 ; wdt:P31 wd:Q103916 .
  FILTER(?opponent != wd:Q1143793)
  ?match_played wdt:P31 wd:Q47152872 ; wdt:P710 wd:Q1143793 ; wdt:P710 ?opponent . MINUS {
    ?match_win wdt:P31 wd:Q47152872 ; wdt:P710 wd:Q1143793 ; wdt:P710 ?opponent ; wdt:P1346 wd:Q1143793 .
  }
  OPTIONAL {
    ?opponent rdfs:label ?opponentLabel .
    FILTER(LANG(?opponentLabel) = "en")
  }
}
LIMIT 10

