PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?opponent ?opponentLabel
WHERE {
  ?opponent wdt:P1412 wd:Q350891 .  # Test-playing nations
  FILTER (?opponent != wd:Q1143793)

  MINUS {
    ?match wdt:P31 wd:Q224337 ;     # T20 International matches
           wdt:P710 wd:Q1143793 ;      # India as participant
           wdt:P710 ?opponent ;
           wdt:P1346 wd:Q1143793 .     # India as winner
  }

  OPTIONAL {
    ?opponent rdfs:label ?opponentLabel .
    FILTER(LANG(?opponentLabel) = "en")
  }
}
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?opponent ?opponentLabel
WHERE {
  # Find cricket teams
  ?opponent wdt:P4182 wd:Q3310 ; # plays cricket
             wdt:P31 wd:Q103916 .  # instance of cricket team
  FILTER (?opponent != wd:Q1143793) # exclude India

  # Ensure India has played T20I matches against them
  ?match_played wdt:P31 wd:Q47152872 ;
                  wdt:P710 wd:Q1143793 ;
                  wdt:P710 ?opponent .

  # Exclude teams India has beaten at least once
  MINUS {
    ?match_win wdt:P31 wd:Q47152872 ;
                  wdt:P710 wd:Q1143793 ;
                  wdt:P710 ?opponent ;
                  wdt:P1346 wd:Q1143793 .
  }

  # Get labels
  OPTIONAL {
    ?opponent rdfs:label ?opponentLabel .
    FILTER (LANG(?opponentLabel) = "en")
  }
}
LIMIT 10
